export function EEZhanShixiaBug() {
  const form = useRef<FormContextType<any>>(null);

  const onFinish = (values: any) => {
    console.log('Success:', values);
  };

  return (
    <div className="container">
      <Form layout="horizontal" initialValues={{ a: '' }} onFinish={onFinish} ref={form}>
        <FormSelectors
          selectors={{
            values: (ctx: FormContextType<any>) => ctx.values,
          }}
        >
          {({ values }) => (
            <Form.Item
              label="test"
              name={['test', 'test1']}
              // validateTrigger={['onSubmit', 'onChange']}
              rules={[
                {
                  validator: (_, valueInfo, callback) => {
                    console.log('test-1', valueInfo);
                    if (valueInfo !== '1') {
                      callback();
                      return true;
                    }
                    callback('error');
                    return false;
                  },
                },
              ]}
            >
              <Input style={{ height: 32, width: '100%' }} />
            </Form.Item>
          )}
        </FormSelectors>

        <Form.Item>
          <Button type="primary" htmlType="submit">
            Submit
          </Button>
        </Form.Item>
      </Form>
    </div>
  );
}

