export function ValuesChange() {
  const form = useRef<
    FormContextType<{
      router?: string;
      method?: string;
      multi?: Array<number>;
    }>
  >(null);

  const handleValueChange = (changedValues: { router?: string; method?: string; multi?: Array<number> }) => {
    if ('router' in changedValues) {
      // 测试三个setValue
      // form.current?.setValues({ method: undefined });
      form.current?.setFieldsValue({ method: undefined, multi: [2] });
      // form.current?.setFieldValue('method', undefined);
    }
  };

  return (
    <div className="App" style={{ width: 600, margin: '0 auto', paddingTop: 32 }}>
      <Form ref={form} initialValues={{}} layout="horizontal" onValuesChange={handleValueChange}>
        <Form.Item label="router" name="router">
          <Select
            options={[
              { label: 'router1', value: '1' },
              { label: 'router2', value: '2' },
            ]}
          />
        </Form.Item>
        <Form.Item label="method" name="method">
          <Select
            options={[
              { label: 'GET', value: 'GET' },
              { label: 'POST', value: 'POST' },
            ]}
          />
        </Form.Item>
        <Form.Item label="multi" name="multi">
          <Checkbox.Group
            options={[
              {
                value: 0,
                label: '0',
              },
              {
                value: 1,
                label: '1',
              },
              {
                value: 2,
                label: '2',
              },
            ]}
          />
        </Form.Item>
      </Form>
    </div>
  );
}

