const UseFormListTableDemoInner = () => {
  const { fields, error, actions } = useFormList({
    name: 'list',
    rowKey: 'uid',
    validate: [
      {
        validate(value) {
          return value?.length ? '' : '至少输入一行';
        },
      },
    ],
  });

  const validateFields = useFormContextSelector(ctx => ctx.validateFields);

  const rules = [
    {
      validator(_rule: any, value: any, callback: any) {
        if (value) {
          return callback();
        }
        return callback(new Error('请填写'));
      },
    },
  ];

  return (
    <Table
      rowKey="key"
      dataSource={fields}
      columns={[
        {
          title: 'name',
          render(_val, field) {
            return (
              <FormItem rules={rules} name={field.name.concat('name')}>
                <Input />
              </FormItem>
            );
          },
        },
        {
          title: 'value',
          render(_val, field) {
            return (
              <FormItem rules={rules} name={field.name.concat('value')}>
                <Input />
              </FormItem>
            );
          },
        },
        {
          title: 'actions',
          render(_val, field) {
            return (
              <div style={{ marginBlockEnd: 28 }}>
                <Button color="danger" type="text" onClick={() => field.remove()}>
                  Delete
                </Button>
              </div>
            );
          },
        },
      ]}
      footer={() => (
        <div>
          <div style={{ display: 'grid', gap: 16, gridAutoFlow: 'column' }}>
            <Button color="primary" onClick={() => actions.push(new DataItem('pushItem'))}>
              Add
            </Button>
            <Button color="primary" onClick={() => actions.unshift(new DataItem('unshiftItem'))}>
              Unshift
            </Button>
            <Button color="primary" onClick={() => actions.swap(1, 2)}>
              交换2/3行
            </Button>
            <Button color="primary" onClick={() => validateFields()}>
              Validate
            </Button>
          </div>
          <FormItemUI help={error} validateStatus="error">
            <></>
          </FormItemUI>
        </div>
      )}
      pagination={false}
    />
  );
};

