export const AllKindsOfValidators = () => (
  <div
    style={{
      maxWidth: 600,
    }}
  >
    <Text>这个例子用来测试几种校验：正则、枚举、长度限制、必填</Text>
    <Form
      layout="horizontal"
      initialValues={{
        username: '',
      }}
    >
      <Form.Item
        required
        label="Username"
        name="username"
        rules={[
          {
            required: true,
            message: 'Please input your username!',
          },
          {
            pattern: /^[a-z]+$/,
          },
          {
            type: 'enum',
            enum: ['a', 'aa', 'abc'],
          },
          {
            max: 3,
            min: 2,
          },
        ]}
      >
        <Input />
      </Form.Item>
    </Form>
  </div>
);

